files.content:
.group {
  display: flex;
  flex-direction: column;
  gap: var(--dimension-space-025);
}

.group--horizontal {
  flex-direction: row;
  gap: var(--dimension-space-100);
}

/* ── Radio item ──────────────────────────────────────────────────────────── */

.radio-item {
  display: flex;
  align-items: center;
  gap: var(--dimension-space-050);
  padding: var(--dimension-space-075);
  height: var(--dimension-size-400);
  box-sizing: border-box;
  cursor: pointer;
  user-select: none;
  border-radius: var(--dimension-radius-075);
  transition: background-color var(--effect-motion-short-2);
  outline: none;
}

.radio-item:hover {
  background-color: var(--color-interaction-hover);
}

.radio-item:active {
  background-color: var(--color-interaction-pressed);
}

.radio-item:focus-visible {
  outline: var(--dimension-stroke-width-025) solid var(--color-interaction-focus);
  outline-offset: var(--dimension-space-025);
}

.radio-item--inactive {
  cursor: not-allowed;
  opacity: 0.5;
  pointer-events: none;
}

/* ── Circle indicator ────────────────────────────────────────────────────── */

.circle {
  width: 20px;
  height: 20px;
  flex-shrink: 0;
  border: 1.5px solid var(--color-foreground-secondary);
  border-radius: var(--dimension-radius-half);
  display: flex;
  align-items: center;
  justify-content: center;
  box-sizing: border-box;
  transition: all var(--effect-motion-short-2);
}

.circle--checked {
  border-color: var(--color-foreground-primary);
}

.dot {
  width: 10px;
  height: 10px;
  border-radius: var(--dimension-radius-half);
  background-color: var(--color-foreground-primary);
}

/* ── Label ───────────────────────────────────────────────────────────────── */

.radio-label {
  flex: 1;
  min-width: 0;
}

import { Component, Prop, Event, EventEmitter, Element, Listen, h, Host } from '@stencil/core';

export interface RadioOption {
  label: string;
  value: string;
  inactive?: boolean;
}

@Component({
  tag: 'ds-radio-group',
  styleUrl: 'RadioGroup.css',
  scoped: true,
})
export class RadioGroup {
  @Element() el!: HTMLElement;

  @Prop() options: RadioOption[] = [];
  @Prop({ mutable: true }) value: string = '';
  @Prop() direction: 'vertical' | 'horizontal' = 'vertical';
  @Prop() inactive: boolean = false;
  @Prop({ attribute: 'aria-label' }) ariaLabel: string | undefined;
  @Prop({ attribute: 'aria-labelledby' }) ariaLabelledby: string | undefined;

  @Event() dsChange!: EventEmitter<string>;

  private get activeItems(): HTMLElement[] {
    return Array.from(this.el.querySelectorAll<HTMLElement>('[data-radio-item]:not([data-inactive])'));
  }

  @Listen('keydown')
  handleKeyDown(e: KeyboardEvent) {
    const items = this.activeItems;
    if (!items.length) return;

    const focused = items.find(item => item === document.activeElement);
    if (!focused) return;

    const idx = items.indexOf(focused);
    let next = -1;

    switch (e.key) {
      case 'ArrowDown':
      case 'ArrowRight':
        e.preventDefault();
        next = (idx + 1) % items.length;
        break;
      case 'ArrowUp':
      case 'ArrowLeft':
        e.preventDefault();
        next = (idx - 1 + items.length) % items.length;
        break;
      case 'Home':
        e.preventDefault();
        next = 0;
        break;
      case 'End':
        e.preventDefault();
        next = items.length - 1;
        break;
    }

    if (next >= 0) {
      items[next].focus();
      const nextValue = items[next].dataset['value'];
      if (nextValue && nextValue !== this.value) {
        this.value = nextValue;
        this.dsChange.emit(nextValue);
      }
    }
  }

  private selectItem(optValue: string) {
    if (this.inactive) return;
    if (optValue !== this.value) {
      this.value = optValue;
      this.dsChange.emit(optValue);
    }
  }

  render() {
    const selectedIdx = this.options.findIndex(o => o.value === this.value);
    const firstActiveIdx = this.options.findIndex(o => !this.inactive && !o.inactive);
    const focusableIdx = selectedIdx >= 0 && !this.inactive && !this.options[selectedIdx]?.inactive
      ? selectedIdx
      : firstActiveIdx;

    return (
      <Host
        role="radiogroup"
        aria-label={this.ariaLabel}
        aria-labelledby={this.ariaLabelledby}
        class={{ group: true, 'group--horizontal': this.direction === 'horizontal' }}
      >
        {this.options.map((opt, i) => {
          const isItemInactive = this.inactive || !!opt.inactive;
          const isChecked = opt.value === this.value;
          const tabIdx = isItemInactive ? -1 : (i === focusableIdx ? 0 : -1);

          return (
            <div
              key={opt.value}
              role="radio"
              aria-checked={String(isChecked)}
              aria-disabled={isItemInactive || undefined}
              tabIndex={tabIdx}
              data-radio-item
              data-value={opt.value}
              data-inactive={isItemInactive || undefined}
              class={{ 'radio-item': true, 'radio-item--inactive': isItemInactive }}
              onClick={() => !isItemInactive && this.selectItem(opt.value)}
              onKeyDown={(e: KeyboardEvent) => {
                if ((e.key === ' ' || e.key === 'Enter') && !isItemInactive) {
                  e.preventDefault();
                  this.selectItem(opt.value);
                }
              }}
            >
              <span class={{ circle: true, 'circle--checked': isChecked }}>
                {isChecked && <span class="dot" />}
              </span>
              <span class="text-body-medium radio-label">{opt.label}</span>
            </div>
          );
        })}
      </Host>
    );
  }
}
